@using sv_7de0f4e8929447e8bc4b6e510adc29a9.Models

<div class="d-flex justify-content-between align-items-center mb-4 position-relative">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var step = i + 1;
        var isCompleted = CompletedSteps.Contains(step);
        var isCurrent = step == CurrentStep;
        var isClickable = isCompleted && !isCurrent;

        <div class="text-center flex-fill position-relative">
            <button type="button"
                    class="btn rounded-circle d-inline-flex align-items-center justify-content-center @StepBadgeClass(step)"
                    style="width: 40px; height: 40px; font-size: 0.85rem;"
                    disabled="@(!isClickable)"
                    @onclick="() => OnStepClicked.InvokeAsync(step)">
                @if (isCompleted && !isCurrent)
                {
                    <span>✓</span>
                }
                else
                {
                    <span>@step</span>
                }
            </button>
            <div class="small mt-1 @StepLabelClass(step)">@StepNames[i]</div>
        </div>
    }
</div>

@code {
    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private string StepBadgeClass(int step) =>
        step == CurrentStep ? "btn-primary" :
        CompletedSteps.Contains(step) ? "btn-success" :
        "btn-outline-secondary";

    private string StepLabelClass(int step) =>
        step == CurrentStep ? "fw-bold text-primary" :
        CompletedSteps.Contains(step) ? "text-success" :
        "text-muted";
}

