{"file_text": "@using sv_7de0f4e8929447e8bc4b6e510adc29a9.Models

<h4 class="mb-3">Review Your Application</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@if (SubmittedId.HasValue)
{
    <div class="alert alert-success text-center">
        <h5 class="alert-heading">Application Submitted!</h5>
        <p class="mb-0">Your application ID is <strong>#@SubmittedId</strong>. We'll be in touch!</p>
    </div>
}
else
{
    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-child-no-border">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-muted small">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <div class="mt-1">@entry.Description</div>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var reference in References)
            {
                <div class="mb-2">
                    <strong>@reference.Name</strong> (@reference.Relationship)
                    <br />
                    <span class="text-muted">@reference.Email · @reference.Phone</span>
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(4)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button type="button" class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
